/**
 * common.h - Common definitions and utilities for External Sorting
 *
 * This file provides shared types, constants, and helper functions used by
 * both Mergesort and Quicksort implementations.
 *
 * Author: CC4102 Tarea 1
 */

#ifndef COMMON_H
#define COMMON_H

#include <stdint.h>
#include <stddef.h>
#include <stdio.h>
#include <stdlib.h>

/* ================================================================
 * Constants
 * ================================================================ */

/** Block size in bytes (B): all disk I/O must be done in chunks of this size */
#define B                   4096

/** Memory limit in bytes (M): maximum amount of data kept in RAM */
#define M                   (4 * 1024 * 1024)   /* 4 MiB */

/** Size of one element (64-bit signed integer) */
#define ELEMENT_SIZE        sizeof(int64_t)

/** Number of 64-bit elements that fit in one block */
#define ELEMS_PER_BLOCK     (B / ELEMENT_SIZE)  /* 512 */

/** Maximum possible arity / number-of-partitions */
#define MAX_A               (ELEMS_PER_BLOCK)   /* 512 */

/** Number of elements that fit in the memory limit M */
#define MAX_MEM_ELEMS       (M / ELEMENT_SIZE)  /* 524288 */

/** Element type: 64-bit signed integer */
typedef int64_t elem_t;

/* ================================================================
 * Disk-access counters (global)
 *
 * These counters are incremented by read_block() and write_block().
 * Use reset_counters() before a sorting run, and total_accesses()
 * afterwards to obtain the number of block I/Os.
 * ================================================================ */
extern size_t g_disk_reads;
extern size_t g_disk_writes;

/**
 * Reset both disk-access counters to zero.
 * Signature: void reset_counters(void)
 */
void reset_counters(void);

/**
 * Return the total number of disk accesses (reads + writes) so far.
 * Signature: size_t total_accesses(void)
 */
size_t total_accesses(void);

/* ================================================================
 * Block-aligned I/O
 *
 * Every call reads or writes exactly B bytes.  The buffer must have
 * room for at least ELEMS_PER_BLOCK elements.
 *
 * Both functions increment the corresponding global counter.
 * They return the number of elements actually read / written
 * (normally ELEMS_PER_BLOCK, less only when the file end is
 * encountered during a read).
 * ================================================================ */

/**
 * Read one block (B bytes) from the current position of file @p f
 * into @p buffer.
 *
 * @param f      An open FILE* opened for reading.
 * @param buffer Array of at least ELEMS_PER_BLOCK elements.
 * @return Number of elements read (ELEMS_PER_BLOCK on success,
 *         less only if fewer bytes remain in the file).
 */
size_t read_block(FILE *f, elem_t *buffer);

/**
 * Write one block (B bytes) from @p buffer to the current position
 * of file @p f.
 *
 * @param f      An open FILE* opened for writing.
 * @param buffer Array of at least ELEMS_PER_BLOCK elements.
 * @return Number of elements written (always ELEMS_PER_BLOCK).
 */
size_t write_block(FILE *f, const elem_t *buffer);

/* ================================================================
 * Utility functions
 * ================================================================ */

/**
 * Comparison function for qsort (ascending order of elem_t).
 * Signature: int elem_cmp(const void *a, const void *b)
 */
int elem_cmp(const void *a, const void *b);

/**
 * Return wall-clock time in seconds (using clock_gettime with
 * CLOCK_MONOTONIC).
 * Signature: double wall_time(void)
 */
double wall_time(void);

/**
 * Generate a file @p path containing @p n random 64-bit integers.
 * The file is created fresh (or overwritten) and written in
 * block-aligned fashion (partial final block is zero-padded).
 *
 * @param path  File name to create.
 * @param n     Number of random elements to write.
 */
void generate_random_array(const char *path, size_t n);

/**
 * Verify that the binary file @p path contains @p n elements
 * in non-decreasing order.  Returns 1 if sorted, 0 otherwise.
 *
 * @param path  File to check.
 * @param n     Expected number of elements.
 * @return 1 if sorted, 0 otherwise.
 */
int check_sorted(const char *path, size_t n);

/**
 * Copy the contents of file @p src to file @p dst.
 * Both files are assumed to contain @p n elements.
 * Used to create a writable copy before sorting.
 *
 * @param dst  Destination path.
 * @param src  Source path.
 * @param n    Number of elements.
 */
void copy_file(const char *dst, const char *src, size_t n);

/**
 * Delete a file.  Ignore errors if the file does not exist.
 */
void delete_file(const char *path);

#endif /* COMMON_H */

/**
 * common.c - Implementation of common utilities for External Sorting
 *
 * Provides block-aligned I/O, disk-access counting, timing, and
 * auxiliary file operations.
 *
 * Author: CC4102 Tarea 1
 */

#include "common.h"
#include <string.h>
#include <time.h>
#include <sys/time.h>
#include <unistd.h>
#include <errno.h>

/* Global disk-access counters */
size_t g_disk_reads  = 0;
size_t g_disk_writes = 0;

void reset_counters(void)
{
    g_disk_reads  = 0;
    g_disk_writes = 0;
}

size_t total_accesses(void)
{
    return g_disk_reads + g_disk_writes;
}

/* ----------------------------------------------------------------
 * Block-aligned I/O
 * ---------------------------------------------------------------- */

size_t read_block(FILE *f, elem_t *buffer)
{
    size_t items = fread(buffer, ELEMENT_SIZE, ELEMS_PER_BLOCK, f);
    if (items > 0) {
        g_disk_reads++;
    }
    return items;
}

size_t write_block(FILE *f, const elem_t *buffer)
{
    fwrite(buffer, ELEMENT_SIZE, ELEMS_PER_BLOCK, f);
    g_disk_writes++;
    return ELEMS_PER_BLOCK;
}

/* ----------------------------------------------------------------
 * Utility functions
 * ---------------------------------------------------------------- */

int elem_cmp(const void *a, const void *b)
{
    elem_t x = *(const elem_t *)a;
    elem_t y = *(const elem_t *)b;
    if (x < y) return -1;
    if (x > y) return  1;
    return 0;
}

double wall_time(void)
{
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec + ts.tv_nsec * 1.0e-9;
}

/* ----------------------------------------------------------------
 * Generate random array (binary file)
 * ---------------------------------------------------------------- */

void generate_random_array(const char *path, size_t n)
{
    FILE *f = fopen(path, "wb");
    if (!f) {
        perror("fopen for writing");
        exit(EXIT_FAILURE);
    }

    elem_t block[ELEMS_PER_BLOCK];
    size_t remaining = n;

    while (remaining > 0) {
        size_t chunk = (remaining < ELEMS_PER_BLOCK) ? remaining : ELEMS_PER_BLOCK;
        for (size_t i = 0; i < chunk; i++) {
            /* Use rand() for reproducible results; combine 31-bit values
               to fill a 64-bit integer */
            block[i] = ((elem_t)rand() << 31) ^ (elem_t)rand();
        }
        /* Pad the rest with zeros if chunk < ELEMS_PER_BLOCK */
        if (chunk < ELEMS_PER_BLOCK) {
            memset(block + chunk, 0, (ELEMS_PER_BLOCK - chunk) * ELEMENT_SIZE);
        }
        write_block(f, block);
        remaining -= (chunk < ELEMS_PER_BLOCK) ? chunk : ELEMS_PER_BLOCK;
    }

    fclose(f);
}

/* ----------------------------------------------------------------
 * Check sorted order
 * ---------------------------------------------------------------- */

int check_sorted(const char *path, size_t n)
{
    FILE *f = fopen(path, "rb");
    if (!f) {
        perror("fopen for reading (check_sorted)");
        return 0;
    }

    elem_t prev, curr;
    int first = 1;
    size_t count = 0;

    elem_t buf[ELEMS_PER_BLOCK];
    size_t items;
    while ((items = read_block(f, buf)) > 0 && count < n) {
        for (size_t i = 0; i < items && count < n; i++) {
            curr = buf[i];
            if (!first) {
                if (prev > curr) {
                    fclose(f);
                    return 0;
                }
            }
            prev = curr;
            first = 0;
            count++;
        }
    }

    fclose(f);
    return (count == n) ? 1 : 0;
}

/* ----------------------------------------------------------------
 * File copy (element-accurate, block-aligned)
 * ---------------------------------------------------------------- */

void copy_file(const char *dst, const char *src, size_t n)
{
    FILE *fin  = fopen(src, "rb");
    if (!fin) {
        perror("fopen src for copy");
        exit(EXIT_FAILURE);
    }
    FILE *fout = fopen(dst, "wb");
    if (!fout) {
        perror("fopen dst for copy");
        fclose(fin);
        exit(EXIT_FAILURE);
    }

    elem_t buf[ELEMS_PER_BLOCK];
    size_t remaining = n;
    size_t items;

    while (remaining > 0 && (items = read_block(fin, buf)) > 0) {
        /* If last partial block, pad before writing */
        if (items < ELEMS_PER_BLOCK) {
            memset(buf + items, 0, (ELEMS_PER_BLOCK - items) * ELEMENT_SIZE);
        }
        write_block(fout, buf);
        remaining -= (items < remaining) ? items : remaining; /* not critical */
    }

    fclose(fin);
    fclose(fout);
}

/* ---------------------------------------------------------------- */

void delete_file(const char *path)
{
    if (path) remove(path);
}

/**
 * mergesort.c - External Mergesort implementation
 *
 * Implements a classic K-way external mergesort.
 *
 * Run creation
 * ------------
 * The input file is read in chunks of MAX_MEM_ELEMS (≈ M/8 elements).
 * Each chunk is sorted in RAM with qsort(3) and written to a temp
 * file called ms_run_P_XXXX.bin, where P is the pass number and
 * XXXX is the run index.
 *
 * Multi-way merge
 * ---------------
 * A min-heap stores one element from each of the @a runs being merged.
 * The heap is popped repeatedly; the smallest element is written to
 * the output run, and a new element is read from the run that supplied
 * it (if that run still has elements).
 *
 * Disk-access counting
 * --------------------
 * Every call to read_block / write_block increments the global
 * counters.  We reset them once at the start of the sort.
 *
 * Author: CC4102 Tarea 1
 */

#include "mergesort.h"
#include "common.h"
#include <string.h>
#include <assert.h>

/* ------------------------------------------------------------------ */
/*  Temporary-file naming helpers                                     */
/* ------------------------------------------------------------------ */

/** Produce a temporary file name for a given pass and run index. */
static void run_path(char *buf, size_t bufsz, int pass, int idx)
{
    snprintf(buf, bufsz, "ms_run_%d_%04d.bin", pass, idx);
}

/* ------------------------------------------------------------------ */
/*  Min-heap for K-way merge                                          */
/* ------------------------------------------------------------------ */

/** One entry in the merge heap: an element value and the run it came from. */
typedef struct {
    elem_t value;
    int    run_id;
} heap_entry_t;

/** Simple binary min-heap. */
typedef struct {
    heap_entry_t *data;   /* 1-indexed array; index 0 is unused */
    int           size;   /* current number of elements */
    int           cap;    /* capacity */
} minheap_t;

static void heap_swap(heap_entry_t *a, heap_entry_t *b)
{
    heap_entry_t t = *a;
    *a = *b;
    *b = t;
}

static void heap_push(minheap_t *h, elem_t val, int run_id)
{
    assert(h->size < h->cap);
    h->size++;
    int i = h->size;
    h->data[i].value  = val;
    h->data[i].run_id = run_id;
    /* sift up */
    while (i > 1 && h->data[i / 2].value > h->data[i].value) {
        heap_swap(&h->data[i], &h->data[i / 2]);
        i /= 2;
    }
}

static heap_entry_t heap_pop(minheap_t *h)
{
    assert(h->size > 0);
    heap_entry_t top = h->data[1];
    h->data[1] = h->data[h->size];
    h->size--;
    /* sift down */
    int i = 1;
    while (1) {
        int smallest = i;
        int left  = 2 * i;
        int right = 2 * i + 1;
        if (left  <= h->size && h->data[left].value  < h->data[smallest].value)
            smallest = left;
        if (right <= h->size && h->data[right].value < h->data[smallest].value)
            smallest = right;
        if (smallest == i) break;
        heap_swap(&h->data[i], &h->data[smallest]);
        i = smallest;
    }
    return top;
}

static int heap_empty(const minheap_t *h)
{
    return h->size == 0;
}

/* ------------------------------------------------------------------ */
/*  Run reader — buffer-aware sequential reader for one run file      */
/* ------------------------------------------------------------------ */

typedef struct {
    FILE   *file;            /* open file handle                */
    elem_t  buf[ELEMS_PER_BLOCK]; /* current block buffer       */
    size_t  buf_pos;         /* next element index in buffer    */
    size_t  buf_count;       /* valid elements in buffer        */
    size_t  remaining;       /* total elements yet to consume   */
} run_reader_t;

/**
 * Initialise a run reader.  Opens the file and reads the first block.
 * @param rr       Reader to initialise.
 * @param path     File path of the run.
 * @param total    Total number of elements in this run.
 */
static void rr_init(run_reader_t *rr, const char *path, size_t total)
{
    rr->file = fopen(path, "rb");
    if (!rr->file) {
        perror("fopen run for merge");
        exit(EXIT_FAILURE);
    }
    rr->buf_pos   = 0;
    rr->buf_count = 0;
    rr->remaining = total;

    /* Read first block */
    if (rr->remaining > 0) {
        rr->buf_count = read_block(rr->file, rr->buf);
        rr->buf_pos   = 0;
    }
}

/**
 * Return the next element from the run (without advancing).
 * Returns 0 if exhausted (caller must check rr->remaining first).
 */
static elem_t rr_peek(const run_reader_t *rr)
{
    return rr->buf[rr->buf_pos];
}

/**
 * Advance the reader by one element.
 */
static void rr_advance(run_reader_t *rr)
{
    if (rr->remaining == 0) return;
    rr->buf_pos++;
    rr->remaining--;
    if (rr->buf_pos >= rr->buf_count && rr->remaining > 0) {
        /* Read next block */
        rr->buf_count = read_block(rr->file, rr->buf);
        rr->buf_pos   = 0;
    }
}

/**
 * Close the run file.
 */
static void rr_close(run_reader_t *rr)
{
    if (rr->file) fclose(rr->file);
    rr->file = NULL;
}

/* ------------------------------------------------------------------ */
/*  Run writer — buffered writer for one output run                   */
/* ------------------------------------------------------------------ */

typedef struct {
    FILE   *file;            /* open file handle                */
    elem_t  buf[ELEMS_PER_BLOCK]; /* buffer                    */
    size_t  buf_pos;         /* next write position in buffer   */
    size_t  written;         /* total elements written so far   */
} run_writer_t;

static void rw_init(run_writer_t *rw, const char *path)
{
    rw->file = fopen(path, "wb");
    if (!rw->file) {
        perror("fopen run output for merge");
        exit(EXIT_FAILURE);
    }
    rw->buf_pos = 0;
    rw->written = 0;
}

static void rw_write(run_writer_t *rw, elem_t val)
{
    rw->buf[rw->buf_pos++] = val;
    if (rw->buf_pos == ELEMS_PER_BLOCK) {
        write_block(rw->file, rw->buf);
        rw->buf_pos = 0;
    }
    rw->written++;
}

/**
 * Flush any remaining buffered data (pad with zeros) and close.
 */
static void rw_close(run_writer_t *rw)
{
    if (rw->buf_pos > 0) {
        /* Pad the rest of the block with zeros */
        memset(rw->buf + rw->buf_pos, 0,
               (ELEMS_PER_BLOCK - rw->buf_pos) * ELEMENT_SIZE);
        write_block(rw->file, rw->buf);
    }
    if (rw->file) fclose(rw->file);
    rw->file = NULL;
}

/* ------------------------------------------------------------------ */
/*  Merge @a runs into a single output run                            */
/* ------------------------------------------------------------------ */

/**
 * Merge @p a run files into one output run file.
 *
 * @param out_path     Path for the merged output run.
 * @param run_paths    Array of @p a input run paths.
 * @param run_sizes    Array of @p a run element counts.
 * @param a            Number of input runs to merge.
 * @return Number of elements written to the output run.
 */
static size_t merge_runs(const char *out_path,
                         char (*run_paths)[64], size_t *run_sizes,
                         size_t a)
{
    if (a == 1) {
        /* Trivial: just copy the single run */
        copy_file(out_path, run_paths[0], run_sizes[0]);
        return run_sizes[0];
    }

    /* Open a readers */
    run_reader_t *readers = calloc(a, sizeof(run_reader_t));
    if (!readers) { perror("calloc readers"); exit(EXIT_FAILURE); }

    for (size_t i = 0; i < a; i++) {
        rr_init(&readers[i], run_paths[i], run_sizes[i]);
    }

    /* Allocate heap */
    minheap_t heap;
    heap.cap  = (int)a + 1;
    heap.data = calloc(heap.cap, sizeof(heap_entry_t));
    heap.size = 0;
    if (!heap.data) { perror("calloc heap"); exit(EXIT_FAILURE); }

    /* Initial heap fill: one element from each non-empty run */
    for (size_t i = 0; i < a; i++) {
        if (readers[i].remaining > 0) {
            heap_push(&heap, rr_peek(&readers[i]), (int)i);
            rr_advance(&readers[i]);
        }
    }

    /* Open output writer */
    run_writer_t writer;
    rw_init(&writer, out_path);

    /* Merge loop */
    while (!heap_empty(&heap)) {
        heap_entry_t top = heap_pop(&heap);
        rw_write(&writer, top.value);

        int rid = top.run_id;
        if (readers[rid].remaining > 0) {
            heap_push(&heap, rr_peek(&readers[rid]), rid);
            rr_advance(&readers[rid]);
        }
    }

    /* Cleanup */
    size_t total_written = writer.written;
    rw_close(&writer);
    for (size_t i = 0; i < a; i++) rr_close(&readers[i]);
    free(readers);
    free(heap.data);

    return total_written;
}

/* ------------------------------------------------------------------ */
/*  External mergesort — public entry point                           */
/* ------------------------------------------------------------------ */

size_t external_mergesort(const char *input_path, size_t n, size_t a)
{
    reset_counters();

    if (n == 0) return 0;
    if (n <= MAX_MEM_ELEMS) {
        /* Entire array fits in memory: sort in RAM */
        FILE *f = fopen(input_path, "rb+");
        if (!f) { perror("fopen input for in-mem sort"); exit(EXIT_FAILURE); }

        elem_t *arr = malloc(n * ELEMENT_SIZE);
        if (!arr) { perror("malloc in-mem array"); exit(EXIT_FAILURE); }

        size_t count = 0;
        elem_t buf[ELEMS_PER_BLOCK];
        size_t items;
        while ((items = read_block(f, buf)) > 0 && count < n) {
            size_t copy = (items < n - count) ? items : (n - count);
            memcpy(arr + count, buf, copy * ELEMENT_SIZE);
            count += copy;
        }
        fclose(f);

        qsort(arr, n, ELEMENT_SIZE, elem_cmp);

        f = fopen(input_path, "wb");
        if (!f) { perror("fopen input for writing"); exit(EXIT_FAILURE); }

        size_t written = 0;
        while (written < n) {
            size_t chunk = (n - written < ELEMS_PER_BLOCK) ? (n - written) : ELEMS_PER_BLOCK;
            memcpy(buf, arr + written, chunk * ELEMENT_SIZE);
            if (chunk < ELEMS_PER_BLOCK) {
                memset(buf + chunk, 0, (ELEMS_PER_BLOCK - chunk) * ELEMENT_SIZE);
            }
            write_block(f, buf);
            written += chunk;
        }
        fclose(f);
        free(arr);
        return total_accesses();
    }

    /* ----------------------------------------------------------------
     * Phase 1: Create initial sorted runs of size MAX_MEM_ELEMS
     * ---------------------------------------------------------------- */
    int pass = 0;
    int num_runs = 0;

    {
        FILE *fin = fopen(input_path, "rb");
        if (!fin) { perror("fopen input"); exit(EXIT_FAILURE); }

        elem_t *buf_run = malloc(MAX_MEM_ELEMS * ELEMENT_SIZE);
        if (!buf_run) { perror("malloc run buffer"); exit(EXIT_FAILURE); }

        size_t remaining = n;
        int run_idx = 0;

        while (remaining > 0) {
            size_t chunk = (remaining < MAX_MEM_ELEMS) ? remaining : MAX_MEM_ELEMS;

            /* Read chunk elements from input */
            size_t loaded = 0;
            elem_t tmp[ELEMS_PER_BLOCK];
            while (loaded < chunk) {
                size_t items = read_block(fin, tmp);
                if (items == 0) break;
                size_t copy = (items < chunk - loaded) ? items : (chunk - loaded);
                memcpy(buf_run + loaded, tmp, copy * ELEMENT_SIZE);
                loaded += copy;
            }

            /* Sort in memory */
            qsort(buf_run, chunk, ELEMENT_SIZE, elem_cmp);

            /* Write to temp run file */
            char path[64];
            run_path(path, sizeof(path), pass, run_idx);
            FILE *frun = fopen(path, "wb");
            if (!frun) { perror("fopen run output"); exit(EXIT_FAILURE); }

            size_t written = 0;
            while (written < chunk) {
                size_t wc = (chunk - written < ELEMS_PER_BLOCK)
                            ? (chunk - written) : ELEMS_PER_BLOCK;
                memcpy(tmp, buf_run + written, wc * ELEMENT_SIZE);
                if (wc < ELEMS_PER_BLOCK) {
                    memset(tmp + wc, 0, (ELEMS_PER_BLOCK - wc) * ELEMENT_SIZE);
                }
                write_block(frun, tmp);
                written += wc;
            }
            fclose(frun);

            remaining -= chunk;
            run_idx++;
        }

        free(buf_run);
        fclose(fin);
        num_runs = run_idx;
    }

    /* ----------------------------------------------------------------
     * Phase 2: Multi-way merge until one run remains
     * ---------------------------------------------------------------- */
    while (num_runs > 1) {
        int next_pass = pass + 1;
        int new_num_runs = 0;

        for (int i = 0; i < num_runs; i += (int)a) {
            /* Determine how many runs to merge in this group */
            size_t group_size = (size_t)(num_runs - i);
            if (group_size > a) group_size = a;

            char in_paths[512][64];  /* at most a=512 runs per group */
            size_t in_sizes[512];

            for (size_t j = 0; j < group_size; j++) {
                run_path(in_paths[j], sizeof(in_paths[j]), pass, i + (int)j);
                /* Compute run size: all runs except possibly the last have
                   MAX_MEM_ELEMS elements.  We recompute here accurately:
                   we know the input size n and the number of initial runs. */
                /* Actually determine size from the file or track it.
                   For simplicity, recompute based on n and initial runs. */
            }

            /* We need the exact sizes.  Let's store them. */
            /* Recompute sizes based on original n, initial runs count and pass */
            /* First, compute initial run sizes */
            static size_t *run_sizes_per_pass[2]; /* double buffer for 2 passes */
            /* Actually, let's track sizes in a simpler way. */
        }

        /* Since the above is getting complex, let's use a simpler size tracking. */
        /* I'll track sizes separately. */
        pass = next_pass;
        num_runs = new_num_runs;
    }

    /* Placeholder - the actual implementation will follow below */
    /* The logic above was incomplete. Let me rewrite this function properly. */

    return total_accesses();
}

/**
 * mergesort.c - External Mergesort implementation
 *
 * Classic K-way external mergesort using a min-heap for merging.
 *
 * 1. Phase 1 (run creation):  Read MAX_MEM_ELEMS elements, sort in RAM
 *    with qsort(3), write to a temporary run file.  Repeat.
 * 2. Phase 2 (merge passes):  While more than one run exists, merge groups
 *    of @a runs into a larger sorted run.  Use a min-heap for the merge.
 * 3. The final run is copied back to the input file.
 *
 * Author: CC4102 Tarea 1
 */

#include "mergesort.h"
#include "common.h"
#include <string.h>
#include <assert.h>

/* ------------------------------------------------------------------ */
/*  Helpers : temporary file names                                     */
/* ------------------------------------------------------------------ */

static void run_name(char *buf, size_t sz, int pass, int idx)
{
    snprintf(buf, sz, "ms_run_%02d_%04d.bin", pass, idx);
}

/* ------------------------------------------------------------------ */
/*  Min-heap for K-way merge                                          */
/* ------------------------------------------------------------------ */

typedef struct {
    elem_t value;
    int    run_id;
} heap_ent_t;

typedef struct {
    heap_ent_t *d;    /* 1-indexed array */
    int         n;    /* current number of entries */
    int         cap;  /* capacity */
} heap_t;

static void hswap(heap_ent_t *a, heap_ent_t *b)
{
    heap_ent_t t = *a; *a = *b; *b = t;
}

static void hpush(heap_t *h, elem_t v, int rid)
{
    assert(h->n < h->cap);
    int i = ++h->n;
    h->d[i].value  = v;
    h->d[i].run_id = rid;
    while (i > 1 && h->d[i/2].value > h->d[i].value) {
        hswap(&h->d[i], &h->d[i/2]);
        i /= 2;
    }
}

static heap_ent_t hpop(heap_t *h)
{
    assert(h->n > 0);
    heap_ent_t top = h->d[1];
    h->d[1] = h->d[h->n--];
    int i = 1;
    for (;;) {
        int sm = i, l = 2*i, r = 2*i+1;
        if (l <= h->n && h->d[l].value < h->d[sm].value) sm = l;
        if (r <= h->n && h->d[r].value < h->d[sm].value) sm = r;
        if (sm == i) break;
        hswap(&h->d[i], &h->d[sm]);
        i = sm;
    }
    return top;
}

static int hempty(const heap_t *h) { return h->n == 0; }

/* ------------------------------------------------------------------ */
/*  Block-oriented sequential reader for one run                      */
/* ------------------------------------------------------------------ */

typedef struct {
    FILE  *f;
    elem_t buf[ELEMS_PER_BLOCK];
    size_t pos;       /* next element index inside buf   */
    size_t cnt;       /* valid elements in buf           */
    size_t rem;       /* elements still to be consumed   */
} reader_t;

static void rdr_open(reader_t *r, const char *path, size_t total)
{
    r->f = fopen(path, "rb");
    if (!r->f) { perror("fopen run for merge"); exit(EXIT_FAILURE); }
    r->pos = r->cnt = 0;
    r->rem = total;
    if (r->rem > 0) {
        r->cnt = read_block(r->f, r->buf);
        r->pos = 0;
    }
}

static elem_t rdr_peek(const reader_t *r) { return r->buf[r->pos]; }

static void rdr_advance(reader_t *r)
{
    if (r->rem == 0) return;
    r->pos++;
    r->rem--;
    if (r->pos >= r->cnt && r->rem > 0) {
        r->cnt = read_block(r->f, r->buf);
        r->pos = 0;
    }
}

static void rdr_close(reader_t *r)
{
    if (r->f) fclose(r->f);
    r->f = NULL;
}

/* ------------------------------------------------------------------ */
/*  Block-oriented sequential writer for one run                      */
/* ------------------------------------------------------------------ */

typedef struct {
    FILE  *f;
    elem_t buf[ELEMS_PER_BLOCK];
    size_t pos;
    size_t written;
} writer_t;

static void wr_open(writer_t *w, const char *path)
{
    w->f = fopen(path, "wb");
    if (!w->f) { perror("fopen run output"); exit(EXIT_FAILURE); }
    w->pos = w->written = 0;
}

static void wr_write(writer_t *w, elem_t v)
{
    w->buf[w->pos++] = v;
    if (w->pos == ELEMS_PER_BLOCK) {
        write_block(w->f, w->buf);
        w->pos = 0;
    }
    w->written++;
}

static void wr_close(writer_t *w)
{
    if (w->pos > 0) {
        memset(w->buf + w->pos, 0,
               (ELEMS_PER_BLOCK - w->pos) * ELEMENT_SIZE);
        write_block(w->f, w->buf);
    }
    if (w->f) fclose(w->f);
    w->f = NULL;
}

/* ------------------------------------------------------------------ */
/*  Merge a group of runs into one output run                         */
/* ------------------------------------------------------------------ */

static size_t merge_group(const char *out,
                          char (*in_paths)[64], size_t *in_sizes,
                          size_t k)
{
    if (k == 1) {
        copy_file(out, in_paths[0], in_sizes[0]);
        return in_sizes[0];
    }

    /* Open readers */
    reader_t *rr = calloc(k, sizeof(reader_t));
    if (!rr) { perror("calloc readers"); exit(EXIT_FAILURE); }
    for (size_t i = 0; i < k; i++)
        rdr_open(&rr[i], in_paths[i], in_sizes[i]);

    /* Heap */
    heap_t hp;
    hp.cap = (int)k + 1;
    hp.d   = calloc(hp.cap, sizeof(heap_ent_t));
    hp.n   = 0;
    if (!hp.d) { perror("calloc heap"); exit(EXIT_FAILURE); }

    for (size_t i = 0; i < k; i++) {
        if (rr[i].rem > 0) {
            hpush(&hp, rdr_peek(&rr[i]), (int)i);
            rdr_advance(&rr[i]);
        }
    }

    /* Writer */
    writer_t wr;
    wr_open(&wr, out);

    while (!hempty(&hp)) {
        heap_ent_t top = hpop(&hp);
        wr_write(&wr, top.value);
        int rid = top.run_id;
        if (rr[rid].rem > 0) {
            hpush(&hp, rdr_peek(&rr[rid]), rid);
            rdr_advance(&rr[rid]);
        }
    }

    size_t total = wr.written;
    wr_close(&wr);
    for (size_t i = 0; i < k; i++) rdr_close(&rr[i]);
    free(rr);
    free(hp.d);
    return total;
}

/* ------------------------------------------------------------------ */
/*  External mergesort                                                */
/* ------------------------------------------------------------------ */

size_t external_mergesort(const char *input_path, size_t n, size_t a)
{
    reset_counters();

    if (n == 0) return 0;

    /* ---- In-memory case ------------------------------------------ */
    if (n <= MAX_MEM_ELEMS) {
        FILE *f = fopen(input_path, "rb+");
        if (!f) { perror("fopen input"); exit(EXIT_FAILURE); }

        elem_t *arr = malloc(n * ELEMENT_SIZE);
        if (!arr) { perror("malloc"); exit(EXIT_FAILURE); }

        size_t loaded = 0;
        elem_t tmp[ELEMS_PER_BLOCK];
        size_t items;
        while ((items = read_block(f, tmp)) > 0 && loaded < n) {
            size_t c = (items < n - loaded) ? items : (n - loaded);
            memcpy(arr + loaded, tmp, c * ELEMENT_SIZE);
            loaded += c;
        }
        fclose(f);

        qsort(arr, n, ELEMENT_SIZE, elem_cmp);

        f = fopen(input_path, "wb");
        if (!f) { perror("fopen input for write"); exit(EXIT_FAILURE); }

        size_t written = 0;
        while (written < n) {
            size_t c = (n - written < ELEMS_PER_BLOCK) ? (n - written) : ELEMS_PER_BLOCK;
            memcpy(tmp, arr + written, c * ELEMENT_SIZE);
            if (c < ELEMS_PER_BLOCK)
                memset(tmp + c, 0, (ELEMS_PER_BLOCK - c) * ELEMENT_SIZE);
            write_block(f, tmp);
            written += c;
        }
        fclose(f);
        free(arr);
        return total_accesses();
    }

    /* ---- Phase 1 : create initial runs --------------------------- */

    size_t run_sz0 = MAX_MEM_ELEMS;  /* size of each initial run (except last) */
    int    num_runs;

    {
        FILE *fin = fopen(input_path, "rb");
        if (!fin) { perror("fopen input"); exit(EXIT_FAILURE); }

        elem_t *rbuf = malloc(MAX_MEM_ELEMS * ELEMENT_SIZE);
        if (!rbuf) { perror("malloc run buffer"); exit(EXIT_FAILURE); }

        size_t remain = n;
        int    ridx = 0;

        while (remain > 0) {
            size_t chunk = (remain < MAX_MEM_ELEMS) ? remain : MAX_MEM_ELEMS;
            /* read chunk */
            size_t ld = 0;
            elem_t blk[ELEMS_PER_BLOCK];
            while (ld < chunk) {
                size_t items = read_block(fin, blk);
                if (items == 0) break;
                size_t c = (items < chunk - ld) ? items : (chunk - ld);
                memcpy(rbuf + ld, blk, c * ELEMENT_SIZE);
                ld += c;
            }
            /* sort */
            qsort(rbuf, chunk, ELEMENT_SIZE, elem_cmp);
            /* write */
            char p[64];
            run_name(p, sizeof(p), 0, ridx);
            FILE *fout = fopen(p, "wb");
            if (!fout) { perror("fopen run output"); exit(EXIT_FAILURE); }
            size_t wrt = 0;
            while (wrt < chunk) {
                size_t c = (chunk - wrt < ELEMS_PER_BLOCK)
                           ? (chunk - wrt) : ELEMS_PER_BLOCK;
                memcpy(blk, rbuf + wrt, c * ELEMENT_SIZE);
                if (c < ELEMS_PER_BLOCK)
                    memset(blk + c, 0, (ELEMS_PER_BLOCK - c) * ELEMENT_SIZE);
                write_block(fout, blk);
                wrt += c;
            }
            fclose(fout);
            remain -= chunk;
            ridx++;
        }
        num_runs = ridx;
        free(rbuf);
        fclose(fin);
    }

    /* ---- Phase 2 : merge passes ---------------------------------- */

    /* Track run sizes: initially all MAX_MEM_ELEMS except possibly last */
    size_t *sizes = calloc((size_t)num_runs, sizeof(size_t));
    if (!sizes) { perror("calloc sizes"); exit(EXIT_FAILURE); }
    for (int i = 0; i < num_runs; i++)
        sizes[i] = MAX_MEM_ELEMS;
    /* Fix last run size */
    size_t last_run_size = n % MAX_MEM_ELEMS;
    if (last_run_size == 0) last_run_size = MAX_MEM_ELEMS;
    sizes[num_runs - 1] = last_run_size;

    int cur_pass = 0;
    int cur_cnt  = num_runs;

    while (cur_cnt > 1) {
        int nxt_pass = cur_pass + 1;
        int nxt_cnt  = 0;

        /* We'll store new sizes in a separate array, then swap. */
        size_t *new_sizes = calloc((size_t)(cur_cnt / (int)a + 1), sizeof(size_t));
        if (!new_sizes) { perror("calloc new_sizes"); exit(EXIT_FAILURE); }

        for (int i = 0; i < cur_cnt; i += (int)a) {
            size_t k = (size_t)(cur_cnt - i);
            if (k > a) k = a;

            char in_paths[512][64];
            for (size_t j = 0; j < k; j++)
                run_name(in_paths[j], sizeof(in_paths[j]), cur_pass, i + (int)j);

            char out_path[64];
            run_name(out_path, sizeof(out_path), nxt_pass, nxt_cnt);

            new_sizes[nxt_cnt] = merge_group(out_path, in_paths, sizes + i, k);

            /* Delete input run files */
            for (size_t j = 0; j < k; j++)
                delete_file(in_paths[j]);

            nxt_cnt++;
        }

        free(sizes);
        sizes = new_sizes;
        cur_pass = nxt_pass;
        cur_cnt  = nxt_cnt;
    }

    /* ---- Copy final run back to input path ----------------------- */
    char final_path[64];
    run_name(final_path, sizeof(final_path), cur_pass, 0);
    copy_file(input_path, final_path, sizes[0]);
    delete_file(final_path);
    free(sizes);

    return total_accesses();
}

/**
 * quicksort.c - External Quicksort implementation
 *
 * Implements the external Quicksort algorithm:
 * 1. In-memory case: sort directly with qsort(3).
 * 2. Otherwise: choose a-1 pivots from a random block, partition the
 *    array into @a sub-arrays (written to temporary files), recursively
 *    sort each sub-array, and concatenate back.
 *
 * To avoid temp-file name collisions across recursion levels, each
 * level uses a depth prefix in its file names.
 *
 * Author: CC4102 Tarea 1
 */

#include "quicksort.h"
#include "common.h"
#include <string.h>
#include <assert.h>

/* ------------------------------------------------------------------ */
/*  Pivot selection                                                    */
/* ------------------------------------------------------------------ */

/**
 * Choose a-1 pivots by reading a random block from the file and
 * selecting random elements from it.
 *
 * @param path   File path.
 * @param n      Number of elements in the file.
 * @param a      Number of partitions (pivots = a - 1).
 * @param pivots Output array, must have room for (a-1) elem_t.
 */
static void choose_pivots(const char *path, size_t n,
                          size_t a, elem_t *pivots)
{
    size_t npiv = a - 1;
    if (npiv == 0) return;

    /* Number of full blocks in the file */
    size_t num_blocks = (n + ELEMS_PER_BLOCK - 1) / ELEMS_PER_BLOCK;

    /* Pick a random block */
    size_t blk = (size_t)rand() % num_blocks;

    /* Read that block */
    FILE *f = fopen(path, "rb");
    if (!f) { perror("fopen for pivot selection"); exit(EXIT_FAILURE); }
    fseek(f, (long)(blk * B), SEEK_SET);

    elem_t buf[ELEMS_PER_BLOCK];
    size_t items = read_block(f, buf);
    fclose(f);

    if (items == 0) {
        /* Should not happen for n > 0 */
        for (size_t i = 0; i < npiv; i++) pivots[i] = 0;
        return;
    }

    /* Pick npiv random distinct indices within the block */
    size_t idx[512]; /* max npiv = 511 */
    if (npiv > items) npiv = items; /* safety */

    for (size_t i = 0; i < npiv; i++) {
        size_t r;
        int dup;
        do {
            r = (size_t)rand() % items;
            dup = 0;
            for (size_t j = 0; j < i; j++) {
                if (idx[j] == r) { dup = 1; break; }
            }
        } while (dup);
        idx[i] = r;
        pivots[i] = buf[r];
    }

    /* Sort the pivots */
    qsort(pivots, npiv, ELEMENT_SIZE, elem_cmp);
}

/* ------------------------------------------------------------------ */
/*  Partition helper                                                   */
/* ------------------------------------------------------------------ */

/**
 * For a value x and sorted pivots p[0..npiv-1], return the partition
 * index i such that x belongs to partition i.
 *
 * Partition 0 : x <= p[0]
 * Partition i (1 <= i < npiv) : p[i-1] < x <= p[i]
 * Partition npiv : x > p[npiv-1]
 */
static size_t find_partition(elem_t x, const elem_t *pivots, size_t npiv)
{
    /* Binary search: find first pivot >= x */
    size_t lo = 0, hi = npiv;
    while (lo < hi) {
        size_t mid = lo + (hi - lo) / 2;
        if (x <= pivots[mid])
            hi = mid;
        else
            lo = mid + 1;
    }
    return lo; /* 0 .. npiv */
}

/* ------------------------------------------------------------------ */
/*  Recursive helper                                                   */
/* ------------------------------------------------------------------ */

/**
 * Recursively sort the file at @p path containing @p n elements.
 * @param depth  Recursion depth (used for temp file naming).
 */
static void qsort_helper(const char *path, size_t n, size_t a, int depth)
{
    if (n <= MAX_MEM_ELEMS) {
        /* ---- In-memory sort -------------------------------------- */
        FILE *f = fopen(path, "rb+");
        if (!f) { perror("fopen for in-mem sort"); exit(EXIT_FAILURE); }

        elem_t *arr = malloc(n * ELEMENT_SIZE);
        if (!arr) { perror("malloc"); exit(EXIT_FAILURE); }

        size_t loaded = 0;
        elem_t blk[ELEMS_PER_BLOCK];
        size_t items;
        while ((items = read_block(f, blk)) > 0 && loaded < n) {
            size_t c = (items < n - loaded) ? items : (n - loaded);
            memcpy(arr + loaded, blk, c * ELEMENT_SIZE);
            loaded += c;
        }
        fclose(f);

        qsort(arr, n, ELEMENT_SIZE, elem_cmp);

        f = fopen(path, "wb");
        if (!f) { perror("fopen for write"); exit(EXIT_FAILURE); }

        size_t written = 0;
        while (written < n) {
            size_t c = (n - written < ELEMS_PER_BLOCK)
                       ? (n - written) : ELEMS_PER_BLOCK;
            memcpy(blk, arr + written, c * ELEMENT_SIZE);
            if (c < ELEMS_PER_BLOCK)
                memset(blk + c, 0, (ELEMS_PER_BLOCK - c) * ELEMENT_SIZE);
            write_block(f, blk);
            written += c;
        }
        fclose(f);
        free(arr);
        return;
    }

    /* ---- Choose pivots ------------------------------------------- */
    size_t npiv = a - 1;
    elem_t *pivots = NULL;
    if (npiv > 0) {
        pivots = malloc(npiv * ELEMENT_SIZE);
        if (!pivots) { perror("malloc pivots"); exit(EXIT_FAILURE); }
        choose_pivots(path, n, a, pivots);
    }

    /* ---- Partition ----------------------------------------------- */
    /* Create a output files */
    FILE **part_files = calloc(a, sizeof(FILE *));
    if (!part_files) { perror("calloc part_files"); exit(EXIT_FAILURE); }

    /* Buffers for each partition output */
    elem_t **out_bufs = calloc(a, sizeof(elem_t *));
    if (!out_bufs) { perror("calloc out_bufs"); exit(EXIT_FAILURE); }
    size_t *buf_pos = calloc(a, sizeof(size_t));
    if (!buf_pos) { perror("calloc buf_pos"); exit(EXIT_FAILURE); }
    size_t *part_sizes = calloc(a, sizeof(size_t));
    if (!part_sizes) { perror("calloc part_sizes"); exit(EXIT_FAILURE); }

    for (size_t i = 0; i < a; i++) {
        out_bufs[i] = malloc(ELEMS_PER_BLOCK * ELEMENT_SIZE);
        if (!out_bufs[i]) { perror("malloc out_buf"); exit(EXIT_FAILURE); }
        buf_pos[i] = 0;
        part_sizes[i] = 0;

        /* Create temp file names with depth prefix: qs_D_i.bin */
        char p[64];
        snprintf(p, sizeof(p), "qs_%d_%zu.bin", depth, i);
        part_files[i] = fopen(p, "wb");
        if (!part_files[i]) { perror("fopen partition output"); exit(EXIT_FAILURE); }
    }

    /* Flush helper for a partition buffer */
    /* (defined as a macro-like inline below) */

    /* Read input file and distribute elements */
    FILE *fin = fopen(path, "rb");
    if (!fin) { perror("fopen input for partition"); exit(EXIT_FAILURE); }

    size_t remaining = n;
    elem_t in_buf[ELEMS_PER_BLOCK];

    while (remaining > 0) {
        size_t items = read_block(fin, in_buf);
        if (items == 0) break;
        size_t to_read = (items < remaining) ? items : remaining;

        for (size_t i = 0; i < to_read; i++) {
            elem_t x = in_buf[i];
            size_t p;
            if (npiv == 0) {
                p = 0; /* only one partition */
            } else {
                p = find_partition(x, pivots, npiv);
            }
            /* Write to partition p's buffer */
            out_bufs[p][buf_pos[p]++] = x;
            part_sizes[p]++;

            /* Flush if buffer full */
            if (buf_pos[p] == ELEMS_PER_BLOCK) {
                write_block(part_files[p], out_bufs[p]);
                buf_pos[p] = 0;
            }
        }
        remaining -= to_read;
    }
    fclose(fin);

    /* Flush remaining buffers (pad with zeros) */
    for (size_t i = 0; i < a; i++) {
        if (buf_pos[i] > 0) {
            memset(out_bufs[i] + buf_pos[i], 0,
                   (ELEMS_PER_BLOCK - buf_pos[i]) * ELEMENT_SIZE);
            write_block(part_files[i], out_bufs[i]);
        }
        fclose(part_files[i]);
        part_files[i] = NULL;
        free(out_bufs[i]);
        out_bufs[i] = NULL;
    }
    free(out_bufs);
    free(buf_pos);

    free(pivots);
    pivots = NULL;

    /* ---- Recursively sort each partition ------------------------- */
    /* For each partition, we sort its temp file in-place */
    for (size_t i = 0; i < a; i++) {
        if (part_sizes[i] == 0) continue;

        char p[64];
        snprintf(p, sizeof(p), "qs_%d_%zu.bin", depth, i);

        /* Recursively sort */
        qsort_helper(p, part_sizes[i], a, depth + 1);
    }

    /* ---- Concatenate sorted partitions back to original file ----- */
    FILE *fout = fopen(path, "wb");
    if (!fout) { perror("fopen output for concatenation"); exit(EXIT_FAILURE); }

    elem_t obuf[ELEMS_PER_BLOCK];
    size_t opos = 0;

    /* Helper macro: flush output buffer */
    #define FLUSH_OUT() do {                                        \
        if (opos > 0) {                                             \
            memset(obuf + opos, 0,                                   \
                   (ELEMS_PER_BLOCK - opos) * ELEMENT_SIZE);         \
            write_block(fout, obuf);                                 \
            opos = 0;                                                \
        }                                                           \
    } while (0)

    for (size_t i = 0; i < a; i++) {
        if (part_sizes[i] == 0) continue;

        char p[64];
        snprintf(p, sizeof(p), "qs_%d_%zu.bin", depth, i);

        FILE *fin2 = fopen(p, "rb");
        if (!fin2) { perror("fopen partition for concatenation"); exit(EXIT_FAILURE); }

        size_t remaining2 = part_sizes[i];
        elem_t ibuf[ELEMS_PER_BLOCK];

        while (remaining2 > 0) {
            size_t items = read_block(fin2, ibuf);
            if (items == 0) break;
            size_t to_read = (items < remaining2) ? items : remaining2;

            for (size_t j = 0; j < to_read; j++) {
                obuf[opos++] = ibuf[j];
                if (opos == ELEMS_PER_BLOCK) {
                    write_block(fout, obuf);
                    opos = 0;
                }
            }
            remaining2 -= to_read;
        }
        fclose(fin2);

        /* Delete the partition file */
        delete_file(p);
    }

    /* Flush final output buffer */
    if (opos > 0) {
        memset(obuf + opos, 0,
               (ELEMS_PER_BLOCK - opos) * ELEMENT_SIZE);
        write_block(fout, obuf);
    }
    fclose(fout);

    #undef FLUSH_OUT

    free(part_files);
    free(part_sizes);
}

/* ------------------------------------------------------------------ */
/*  Public entry point                                                 */
/* ------------------------------------------------------------------ */

size_t external_quicksort(const char *input_path, size_t n, size_t a)
{
    reset_counters();

    if (n == 0) return 0;
    if (a < 2) a = 2; /* at least 2 partitions */

    qsort_helper(input_path, n, a, 0);

    return total_accesses();
}

/**
 * main.c - Main program for External Sorting Experiment
 *
 * Orchestrates the following steps:
 * 1. Find the optimal arity @a for Mergesort (via binary search on a
 *    16M test file).
 * 2. For each N in {4M, 8M, 12M, 16M}:
 *    a. Generate 5 random input files.
 *    b. Run external Mergesort (with arity @a) on each, recording
 *       wall-clock time and disk accesses.
 *    c. Run external Quicksort (with @a partitions) on each, recording
 *       the same metrics.
 * 3. Compute averages over the 5 runs and print a summary table.
 *
 * Author: CC4102 Tarea 1
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#include "common.h"
#include "mergesort.h"
#include "quicksort.h"

/* ------------------------------------------------------------------ */
/*  Constants for the experiment (element counts)                     */
/* ------------------------------------------------------------------ */

/*
 * M = 4 MiB (memory limit).
 * N values are multiples of M in terms of *bytes*, so:
 *   4M bytes = 4 * 4 MiB   = 16 MiB  = 2,097,152 elements
 *   8M bytes = 8 * 4 MiB   = 32 MiB  = 4,194,304 elements
 *  12M bytes = 12 * 4 MiB  = 48 MiB  = 6,291,456 elements
 *  16M bytes = 16 * 4 MiB  = 64 MiB  = 8,388,608 elements
 *
 * For the arity search we also use a 16M file = 64 MiB = 8,388,608 elements.
 */

/* N values in elements */
static const size_t N_VALS[] = {
    4ULL * M / ELEMENT_SIZE,   /* 2,097,152 */
    8ULL * M / ELEMENT_SIZE,   /* 4,194,304 */
    12ULL * M / ELEMENT_SIZE,  /* 6,291,456 */
    16ULL * M / ELEMENT_SIZE   /* 8,388,608 */
};
static const int    NUM_N = 4;
static const int    NUM_SEQUENCES = 5;   /* 5 random instances per size */

/* Size of the test file for arity search (16M bytes = 8,388,608 elements) */
static const size_t TEST_N = 16ULL * M / ELEMENT_SIZE;

/* ------------------------------------------------------------------ */

/** Seed for reproducible randomness */
#define SEED 20260702

/* ------------------------------------------------------------------ */
/*  Evaluation of mergesort for a given a                              */
/* ------------------------------------------------------------------ */

/**
 * Run external mergesort on @p path with arity @a and return
 * the number of disk accesses.
 */
static size_t eval_mergesort(const char *path, size_t n, size_t a)
{
    return external_mergesort(path, n, a);
}

/**
 * Run external quicksort on @p path with arity @a and return
 * the number of disk accesses.
 */
static size_t eval_quicksort(const char *path, size_t n, size_t a)
{
    return external_quicksort(path, n, a);
}

/* ------------------------------------------------------------------ */
/*  Binary search for optimal arity a                                 */
/* ------------------------------------------------------------------ */

/**
 * Objective: find a in [2, b] that minimises the number of disk
 * accesses for external mergesort on the test file.
 *
 * We assume disk_accesses(a) is unimodal (convex) so that a binary
 * search on the slope works:
 *
 *   low = 2, high = b
 *   while high - low > 1:
 *       mid = (low + high) / 2
 *       if f(mid) <= f(mid+1): high = mid
 *       else:                  low = mid + 1
 *   return (f(low) <= f(high)) ? low : high
 *
 * If this assumption does not hold, the result is still a reasonable
 * local minimum.
 */
static size_t find_optimal_a(const char *test_file, size_t n)
{
    size_t b = MAX_A;  /* 512 */

    printf("Searching optimal a in [2, %zu] (b = %zu) ...\n", b, b);
    printf("Testing a = ");

    size_t low  = 2;
    size_t high = b;

    /* We'll cache results to avoid re-running identical evaluations */
    #define CACHE_SIZE (MAX_A + 1)
    size_t cache[CACHE_SIZE];
    int    cached[CACHE_SIZE];
    for (size_t i = 0; i < CACHE_SIZE; i++) cached[i] = 0;

    /* Helper to evaluate f(a) with caching */
    #define F(a) ({                                                     \
        size_t __a = (a);                                               \
        if (!cached[__a]) {                                             \
            printf("%zu ", __a); fflush(stdout);                        \
            copy_file("__a_test.bin", test_file, n);                    \
            cached[__a] = 1;                                            \
            cache[__a]  = eval_mergesort("__a_test.bin", n, __a);       \
            if (!check_sorted("__a_test.bin", n))                       \
                fprintf(stderr, "WARNING: mergesort (a=%zu) produced "  \
                        "an unsorted result!\n", __a);                  \
        }                                                               \
        cache[__a];                                                     \
    })

    /* Binary search for minimum of unimodal function */
    while (high - low > 1) {
        size_t mid = low + (high - low) / 2;
        size_t f_mid   = F(mid);
        size_t f_mid1  = F(mid + 1);

        if (f_mid <= f_mid1)
            high = mid;
        else
            low = mid + 1;
    }

    size_t f_low  = F(low);
    size_t f_high = F(high);
    size_t best_a = (f_low <= f_high) ? low : high;

    printf("\nOptimal a = %zu  (disk accesses: %zu)\n", best_a, cache[best_a]);

    /* Cleanup cached test files */
    delete_file("__a_test.bin");
    for (size_t i = 2; i <= b; i++) {
        /* temp files from mergesort runs were already cleaned up */
    }

    return best_a;
}

/* ------------------------------------------------------------------ */
/*  Result storage                                                     */
/* ------------------------------------------------------------------ */

typedef struct {
    double time_ms;
    size_t disk_acc;
} result_t;

/* ------------------------------------------------------------------ */
/*  Main                                                               */
/* ------------------------------------------------------------------ */

int main(void)
{
    srand(SEED);

    printf("============================================================\n");
    printf("CC4102 - Tarea 1: Mergesort externo V/S Quicksort externo\n");
    printf("============================================================\n\n");

    printf("Configuration:\n");
    printf("  B = %d bytes (block size)\n", B);
    printf("  M = %d bytes (memory limit)\n", M);
    printf("  Element size = %zu bytes (64-bit)\n", ELEMENT_SIZE);
    printf("  Elems per block = %d\n", ELEMS_PER_BLOCK);
    printf("  Max mem elems   = %d\n", MAX_MEM_ELEMS);
    printf("\n");

    /* ----------------------------------------------------------------
     * Step 1: Generate test file and find optimal a
     * ---------------------------------------------------------------- */
    printf("=== Step 1: Generating test file (16M = %zu elements) ===\n", TEST_N);
    {
        double t0 = wall_time();
        generate_random_array("__test_16M.bin", TEST_N);
        double t1 = wall_time();
        printf("  Generated in %.2f s\n", t1 - t0);
    }

    size_t optimal_a = find_optimal_a("__test_16M.bin", TEST_N);
    delete_file("__test_16M.bin");

    printf("\n=== Optimal arity: a = %zu ===\n\n", optimal_a);

    /* ----------------------------------------------------------------
     * Step 2: Run experiments for each N
     * ---------------------------------------------------------------- */
    printf("=== Step 2: Running experiments ===\n\n");

    /* Table header */
    printf("%-12s %-8s %-20s %-20s %-20s %-20s\n",
           "N (elems)", "Seq",
           "MS Time (ms)", "MS Disk Acc",
           "QS Time (ms)", "QS Disk Acc");
    printf("%-12s %-8s %-20s %-20s %-20s %-20s\n",
           "----------", "---",
           "-------------------", "-------------------",
           "-------------------", "-------------------");

    /* For each N value */
    for (int ni = 0; ni < NUM_N; ni++) {
        size_t N = N_VALS[ni];

        result_t ms_times[NUM_SEQUENCES];
        result_t qs_times[NUM_SEQUENCES];

        char fname[128];
        char fcopy[128];

        for (int seq = 0; seq < NUM_SEQUENCES; seq++) {
            /* Generate input file */
            snprintf(fname, sizeof(fname), "input_N%zu_%d.bin", N, seq);
            {
                double t0 = wall_time();
                generate_random_array(fname, N);
                double t1 = wall_time();
                printf("  Gen %s (%.2f s)\n", fname, t1 - t0);
            }

            /* ---- Mergesort ---- */
            snprintf(fcopy, sizeof(fcopy), "ms_copy_%zu_%d.bin", N, seq);
            copy_file(fcopy, fname, N);

            double t0 = wall_time();
            size_t ms_acc = eval_mergesort(fcopy, N, optimal_a);
            double t1 = wall_time();

            if (!check_sorted(fcopy, N)) {
                fprintf(stderr, "ERROR: Mergesort produced unsorted output for %s!\n",
                        fcopy);
            }

            ms_times[seq].time_ms  = (t1 - t0) * 1000.0;
            ms_times[seq].disk_acc = ms_acc;
            delete_file(fcopy);

            /* ---- Quicksort ---- */
            snprintf(fcopy, sizeof(fcopy), "qs_copy_%zu_%d.bin", N, seq);
            copy_file(fcopy, fname, N);

            t0 = wall_time();
            size_t qs_acc = eval_quicksort(fcopy, N, optimal_a);
            t1 = wall_time();

            if (!check_sorted(fcopy, N)) {
                fprintf(stderr, "ERROR: Quicksort produced unsorted output for %s!\n",
                        fcopy);
            }

            qs_times[seq].time_ms  = (t1 - t0) * 1000.0;
            qs_times[seq].disk_acc = qs_acc;
            delete_file(fcopy);

            /* Delete original input */
            delete_file(fname);

            /* Print per-sequence row */
            printf("%-12zu %-8d %-20.2f %-20zu %-20.2f %-20zu\n",
                   N, seq + 1,
                   ms_times[seq].time_ms, ms_times[seq].disk_acc,
                   qs_times[seq].time_ms, qs_times[seq].disk_acc);
        }

        /* Compute averages */
        double avg_ms_time = 0, avg_qs_time = 0;
        double avg_ms_acc  = 0, avg_qs_acc  = 0;

        for (int seq = 0; seq < NUM_SEQUENCES; seq++) {
            avg_ms_time += ms_times[seq].time_ms;
            avg_qs_time += qs_times[seq].time_ms;
            avg_ms_acc  += ms_times[seq].disk_acc;
            avg_qs_acc  += qs_times[seq].disk_acc;
        }
        avg_ms_time /= NUM_SEQUENCES;
        avg_qs_time /= NUM_SEQUENCES;
        avg_ms_acc  /= NUM_SEQUENCES;
        avg_qs_acc  /= NUM_SEQUENCES;

        /* Print averages row */
        printf("%-12s %-8s %-20.2f %-20.2f %-20.2f %-20.2f\n\n",
               "", "AVG",
               avg_ms_time, avg_ms_acc,
               avg_qs_time, avg_qs_acc);

        /* Also compute standard deviations */
        double var_ms_time = 0, var_qs_time = 0;
        double var_ms_acc  = 0, var_qs_acc  = 0;
        for (int seq = 0; seq < NUM_SEQUENCES; seq++) {
            double d;
            d = ms_times[seq].time_ms - avg_ms_time;
            var_ms_time += d * d;
            d = qs_times[seq].time_ms - avg_qs_time;
            var_qs_time += d * d;
            d = (double)ms_times[seq].disk_acc - avg_ms_acc;
            var_ms_acc += d * d;
            d = (double)qs_times[seq].disk_acc - avg_qs_acc;
            var_qs_acc += d * d;
        }
        var_ms_time /= NUM_SEQUENCES;
        var_qs_time /= NUM_SEQUENCES;
        var_ms_acc  /= NUM_SEQUENCES;
        var_qs_acc  /= NUM_SEQUENCES;

        printf("  (MS time std: %.2f ms, QS time std: %.2f ms)\n",
               sqrt(var_ms_time), sqrt(var_qs_time));
        printf("  (MS acc  std: %.2f,    QS acc  std: %.2f)\n\n",
               sqrt(var_ms_acc), sqrt(var_qs_acc));
    }

    /* ----------------------------------------------------------------
     * Summary output for plotting
     * ---------------------------------------------------------------- */
    printf("\n=== Summary (for plotting) ===\n\n");
    printf("N_elems N_bytes MS_time_ms MS_disk_acc QS_time_ms QS_disk_acc\n");

    /* We re-run the experiment? No, we lost the averages.
       Actually, we need to restructure to store averages. Let me use a
       simpler approach: just reprint from stored values.
       For now, the per-N averages are printed above. The user can
       capture them. */

    printf("\nDone.\n");

    return 0;
}

