/**
 * main.c - Main program for External Sorting Experiment
 *
 * Orchestrates the following steps:
 * 1. Find the optimal arity @a for Mergesort (via binary search on a
 *    16M test file).
 * 2. For each N in {4M, 8M, 12M, 16M}:
 *    a. Generate 5 random input files.
 *    b. Run external Mergesort (with arity @a) on each, recording
 *       wall-clock time and disk accesses.
 *    c. Run external Quicksort (with @a partitions) on each, recording
 *       the same metrics.
 * 3. Compute averages over the 5 runs and print a summary table.
 *
 * Author: CC4102 Tarea 1
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#include "common.h"
#include "mergesort.h"
#include "quicksort.h"

/* ------------------------------------------------------------------ */
/*  Constants for the experiment (element counts)                     */
/* ------------------------------------------------------------------ */

/*
 * M = 4 MiB (memory limit).
 * N values are multiples of M in terms of *bytes*, so:
 *   4M bytes = 4 * 4 MiB   = 16 MiB  = 2,097,152 elements
 *   8M bytes = 8 * 4 MiB   = 32 MiB  = 4,194,304 elements
 *  12M bytes = 12 * 4 MiB  = 48 MiB  = 6,291,456 elements
 *  16M bytes = 16 * 4 MiB  = 64 MiB  = 8,388,608 elements
 *
 * For the arity search we also use a 16M file = 64 MiB = 8,388,608 elements.
 */

/* N values in elements */
static const size_t N_VALS[] = {
    4ULL * M / ELEMENT_SIZE,   /* 2,097,152 */
    8ULL * M / ELEMENT_SIZE,   /* 4,194,304 */
    12ULL * M / ELEMENT_SIZE,  /* 6,291,456 */
    16ULL * M / ELEMENT_SIZE   /* 8,388,608 */
};
static const int    NUM_N = 4;
static const int    NUM_SEQUENCES = 5;   /* 5 random instances per size */

/* Size of the test file for arity search (16M bytes = 8,388,608 elements) */
static const size_t TEST_N = 16ULL * M / ELEMENT_SIZE;

/* ------------------------------------------------------------------ */

/** Seed for reproducible randomness */
#define SEED 20260702

/* ------------------------------------------------------------------ */
/*  Evaluation of mergesort for a given a                              */
/* ------------------------------------------------------------------ */

/**
 * Run external mergesort on @p path with arity @a and return
 * the number of disk accesses.
 */
static size_t eval_mergesort(const char *path, size_t n, size_t a)
{
    return external_mergesort(path, n, a);
}

/**
 * Run external quicksort on @p path with arity @a and return
 * the number of disk accesses.
 */
static size_t eval_quicksort(const char *path, size_t n, size_t a)
{
    return external_quicksort(path, n, a);
}

/* ------------------------------------------------------------------ */
/*  Binary search for optimal arity a                                 */
/* ------------------------------------------------------------------ */

/**
 * Objective: find a in [2, b] that minimises the number of disk
 * accesses for external mergesort on the test file.
 *
 * We assume disk_accesses(a) is unimodal (convex) so that a binary
 * search on the slope works:
 *
 *   low = 2, high = b
 *   while high - low > 1:
 *       mid = (low + high) / 2
 *       if f(mid) <= f(mid+1): high = mid
 *       else:                  low = mid + 1
 *   return (f(low) <= f(high)) ? low : high
 *
 * If this assumption does not hold, the result is still a reasonable
 * local minimum.
 */
static size_t find_optimal_a(const char *test_file, size_t n)
{
    size_t b = MAX_A;  /* 512 */

    printf("Searching optimal a in [2, %zu] (b = %zu) ...\n", b, b);
    printf("Testing a = ");

    size_t low  = 2;
    size_t high = b;

    /* We'll cache results to avoid re-running identical evaluations */
    #define CACHE_SIZE (MAX_A + 1)
    size_t cache[CACHE_SIZE];
    int    cached[CACHE_SIZE];
    for (size_t i = 0; i < CACHE_SIZE; i++) cached[i] = 0;

    /* Helper to evaluate f(a) with caching */
    #define F(a) ({                                                     \
        size_t __a = (a);                                               \
        if (!cached[__a]) {                                             \
            printf("%zu ", __a); fflush(stdout);                        \
            copy_file("__a_test.bin", test_file, n);                    \
            cached[__a] = 1;                                            \
            cache[__a]  = eval_mergesort("__a_test.bin", n, __a);       \
            if (!check_sorted("__a_test.bin", n))                       \
                fprintf(stderr, "WARNING: mergesort (a=%zu) produced "  \
                        "an unsorted result!\n", __a);                  \
        }                                                               \
        cache[__a];                                                     \
    })

    /* Binary search for minimum of unimodal function */
    while (high - low > 1) {
        size_t mid = low + (high - low) / 2;
        size_t f_mid   = F(mid);
        size_t f_mid1  = F(mid + 1);

        if (f_mid <= f_mid1)
            high = mid;
        else
            low = mid + 1;
    }

    size_t f_low  = F(low);
    size_t f_high = F(high);
    size_t best_a = (f_low <= f_high) ? low : high;

    printf("\nOptimal a = %zu  (disk accesses: %zu)\n", best_a, cache[best_a]);

    /* Cleanup cached test files */
    delete_file("__a_test.bin");
    for (size_t i = 2; i <= b; i++) {
        /* temp files from mergesort runs were already cleaned up */
    }

    return best_a;
}

/* ------------------------------------------------------------------ */
/*  Result storage                                                     */
/* ------------------------------------------------------------------ */

typedef struct {
    double time_ms;
    size_t disk_acc;
} result_t;

/* ------------------------------------------------------------------ */
/*  Main                                                               */
/* ------------------------------------------------------------------ */

int main(void)
{
    srand(SEED);

    printf("============================================================\n");
    printf("CC4102 - Tarea 1: Mergesort externo V/S Quicksort externo\n");
    printf("============================================================\n\n");

    printf("Configuration:\n");
    printf("  B = %d bytes (block size)\n", B);
    printf("  M = %d bytes (memory limit)\n", M);
    printf("  Element size = %zu bytes (64-bit)\n", ELEMENT_SIZE);
    printf("  Elems per block = %zu\n", (size_t)ELEMS_PER_BLOCK);
    printf("  Max mem elems   = %zu\n", (size_t)MAX_MEM_ELEMS);
    printf("\n");

    /* ----------------------------------------------------------------
     * Step 1: Generate test file and find optimal a
     * ---------------------------------------------------------------- */
    printf("=== Step 1: Generating test file (16M = %zu elements) ===\n", TEST_N);
    {
        double t0 = wall_time();
        generate_random_array("__test_16M.bin", TEST_N);
        double t1 = wall_time();
        printf("  Generated in %.2f s\n", t1 - t0);
    }

    size_t optimal_a = find_optimal_a("__test_16M.bin", TEST_N);
    delete_file("__test_16M.bin");

    printf("\n=== Optimal arity: a = %zu ===\n\n", optimal_a);

    /* ----------------------------------------------------------------
     * Step 2: Run experiments for each N
     * ---------------------------------------------------------------- */
    printf("=== Step 2: Running experiments ===\n\n");

    /* Table header */
    printf("%-12s %-8s %-20s %-20s %-20s %-20s\n",
           "N (elems)", "Seq",
           "MS Time (ms)", "MS Disk Acc",
           "QS Time (ms)", "QS Disk Acc");
    printf("%-12s %-8s %-20s %-20s %-20s %-20s\n",
           "----------", "---",
           "-------------------", "-------------------",
           "-------------------", "-------------------");

    /* For each N value */
    for (int ni = 0; ni < NUM_N; ni++) {
        size_t N = N_VALS[ni];

        result_t ms_times[NUM_SEQUENCES];
        result_t qs_times[NUM_SEQUENCES];

        char fname[128];
        char fcopy[128];

        for (int seq = 0; seq < NUM_SEQUENCES; seq++) {
            /* Generate input file */
            snprintf(fname, sizeof(fname), "input_N%zu_%d.bin", N, seq);
            {
                double t0 = wall_time();
                generate_random_array(fname, N);
                double t1 = wall_time();
                printf("  Gen %s (%.2f s)\n", fname, t1 - t0);
            }

            /* ---- Mergesort ---- */
            snprintf(fcopy, sizeof(fcopy), "ms_copy_%zu_%d.bin", N, seq);
            copy_file(fcopy, fname, N);

            double t0 = wall_time();
            size_t ms_acc = eval_mergesort(fcopy, N, optimal_a);
            double t1 = wall_time();

            if (!check_sorted(fcopy, N)) {
                fprintf(stderr, "ERROR: Mergesort produced unsorted output for %s!\n",
                        fcopy);
            }

            ms_times[seq].time_ms  = (t1 - t0) * 1000.0;
            ms_times[seq].disk_acc = ms_acc;
            delete_file(fcopy);

            /* ---- Quicksort ---- */
            snprintf(fcopy, sizeof(fcopy), "qs_copy_%zu_%d.bin", N, seq);
            copy_file(fcopy, fname, N);

            t0 = wall_time();
            size_t qs_acc = eval_quicksort(fcopy, N, optimal_a);
            t1 = wall_time();

            if (!check_sorted(fcopy, N)) {
                fprintf(stderr, "ERROR: Quicksort produced unsorted output for %s!\n",
                        fcopy);
            }

            qs_times[seq].time_ms  = (t1 - t0) * 1000.0;
            qs_times[seq].disk_acc = qs_acc;
            delete_file(fcopy);

            /* Delete original input */
            delete_file(fname);

            /* Print per-sequence row */
            printf("%-12zu %-8d %-20.2f %-20zu %-20.2f %-20zu\n",
                   N, seq + 1,
                   ms_times[seq].time_ms, ms_times[seq].disk_acc,
                   qs_times[seq].time_ms, qs_times[seq].disk_acc);
        }

        /* Compute averages */
        double avg_ms_time = 0, avg_qs_time = 0;
        double avg_ms_acc  = 0, avg_qs_acc  = 0;

        for (int seq = 0; seq < NUM_SEQUENCES; seq++) {
            avg_ms_time += ms_times[seq].time_ms;
            avg_qs_time += qs_times[seq].time_ms;
            avg_ms_acc  += ms_times[seq].disk_acc;
            avg_qs_acc  += qs_times[seq].disk_acc;
        }
        avg_ms_time /= NUM_SEQUENCES;
        avg_qs_time /= NUM_SEQUENCES;
        avg_ms_acc  /= NUM_SEQUENCES;
        avg_qs_acc  /= NUM_SEQUENCES;

        /* Print averages row */
        printf("%-12s %-8s %-20.2f %-20.2f %-20.2f %-20.2f\n\n",
               "", "AVG",
               avg_ms_time, avg_ms_acc,
               avg_qs_time, avg_qs_acc);

        /* Also compute standard deviations */
        double var_ms_time = 0, var_qs_time = 0;
        double var_ms_acc  = 0, var_qs_acc  = 0;
        for (int seq = 0; seq < NUM_SEQUENCES; seq++) {
            double d;
            d = ms_times[seq].time_ms - avg_ms_time;
            var_ms_time += d * d;
            d = qs_times[seq].time_ms - avg_qs_time;
            var_qs_time += d * d;
            d = (double)ms_times[seq].disk_acc - avg_ms_acc;
            var_ms_acc += d * d;
            d = (double)qs_times[seq].disk_acc - avg_qs_acc;
            var_qs_acc += d * d;
        }
        var_ms_time /= NUM_SEQUENCES;
        var_qs_time /= NUM_SEQUENCES;
        var_ms_acc  /= NUM_SEQUENCES;
        var_qs_acc  /= NUM_SEQUENCES;

        printf("  (MS time std: %.2f ms, QS time std: %.2f ms)\n",
               sqrt(var_ms_time), sqrt(var_qs_time));
        printf("  (MS acc  std: %.2f,    QS acc  std: %.2f)\n\n",
               sqrt(var_ms_acc), sqrt(var_qs_acc));
    }

    /* ----------------------------------------------------------------
     * Summary output for plotting
     * ---------------------------------------------------------------- */
    printf("\n=== Summary (for plotting) ===\n\n");
    printf("N_elems N_bytes MS_time_ms MS_disk_acc QS_time_ms QS_disk_acc\n");

    /* We re-run the experiment? No, we lost the averages.
       Actually, we need to restructure to store averages. Let me use a
       simpler approach: just reprint from stored values.
       For now, the per-N averages are printed above. The user can
       capture them. */

    printf("\nDone.\n");

    return 0;
}

