 * main.c - Main program for External Sorting Experiment
 *
 * Orchestrates the following steps:
 * 1. Find the optimal arity @a for Mergesort (via binary search on a
 *    16M test file).
 * 2. For each N in {4M, 8M, 12M, 16M}:
 *    a. Generate 5 random input files.
 *    b. Run external Mergesort (with arity @a) on each, recording
 *       wall-clock time and disk accesses.
 *    c. Run external Quicksort (with @a partitions) on each, recording
 *       the same metrics.
 * 3. Compute averages over the 5 runs and print a summary table.
 *
 * Author: CC4102 Tarea 1
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#include "common.h"
#include "mergesort.h"
#include "quicksort.h"

/* ------------------------------------------------------------------ */
/*  Constants for the experiment (element counts)                     */
/* ------------------------------------------------------------------ */

/*
 * M = 4 MiB (memory limit).
 * N values are multiples of M in terms of *bytes*:
 *   4M bytes = 4 * 4 MiB   = 16 MiB  = 2,097,152 elements
 *   8M bytes = 8 * 4 MiB   = 32 MiB  = 4,194,304 elements
 *  12M bytes = 12 * 4 MiB  = 48 MiB  = 6,291,456 elements
 *  16M bytes = 16 * 4 MiB  = 64 MiB  = 8,388,608 elements
 */

static const size_t N_VALS[] = {
    4ULL * M / ELEMENT_SIZE,   /* 2,097,152 */
    8ULL * M / ELEMENT_SIZE,   /* 4,194,304 */
    12ULL * M / ELEMENT_SIZE,  /* 6,291,456 */
    16ULL * M / ELEMENT_SIZE   /* 8,388,608 */
};
static const int NUM_N          = 4;
static const int NUM_SEQUENCES  = 5;

/* Size of the test file for arity search (16M bytes = 8,388,608 elements) */
static const size_t TEST_N = 16ULL * M / ELEMENT_SIZE;

/* Seed for reproducible randomness */
#define SEED 20260702

/* ------------------------------------------------------------------ */
/*  Per-N result storage                                              */
/* ------------------------------------------------------------------ */

typedef struct {
    double   time_ms;     /* average time in ms */
    double   time_std;    /* standard deviation  */
    double   disk_acc;    /* average disk accesses */
    double   disk_std;    /* standard deviation */
} avg_result_t;

/* ------------------------------------------------------------------ */
/*  Binary search for optimal arity a                                 */
/* ------------------------------------------------------------------ */

/**
 * Evaluate mergesort on the given file and return disk accesses.
 * The file is sorted in-place.
 */
static size_t eval_a(const char *path, size_t n, size_t a)
{
    return external_mergesort(path, n, a);
}

/**
 * Compute f(a) = disk accesses for mergesort on the test file.
 * Uses a cache to avoid re-running for the same @p a.
 *
 * @param test_file  Path to the original (unsorted) test file.
 * @param n          Number of elements.
 * @param a          Arity to test.
 * @param cache      Pre-allocated cache array (size MAX_A+1).
 * @param cached     Boolean array tracking which a have been evaluated.
 * @return Number of disk accesses.
 */
static size_t f_a(const char *test_file, size_t n, size_t a,
                  size_t *cache, int *cached)
{
    if (a < 2) a = 2;
    if (a > MAX_A) a = MAX_A;

    if (!cached[a]) {
        printf("%zu ", a);
        fflush(stdout);

        /* Copy the original unsorted test file */
        copy_file("__a_test.bin", test_file, n);

        /* Run mergesort and record accesses */
        cache[a] = eval_a("__a_test.bin", n, a);

        /* Verify correctness */
        if (!check_sorted("__a_test.bin", n)) {
            fprintf(stderr, "\nWARNING: mergesort (a=%zu) produced "
                            "an unsorted result!\n", a);
        }
        cached[a] = 1;
    }
    return cache[a];
}

/**
 * Find the optimal arity a in [2, b] that minimises disk accesses
 * for external mergesort on a test file of size @p n.
 *
 * Uses binary search on the slope, assuming the cost function
 * is unimodal (convex).
 */
static size_t find_optimal_a(const char *test_file, size_t n)
{
    size_t b = MAX_A;  /* 512 */

    printf("Searching optimal a in [2, %zu] (b = %zu) ...\n", b, b);
    printf("Testing a = ");

    /* Cache */
    size_t cache[MAX_A + 1];
    int    cached[MAX_A + 1];
    for (size_t i = 0; i <= MAX_A; i++) cached[i] = 0;

    size_t low  = 2;
    size_t high = b;

    /* Binary search for the minimum of a unimodal function */
    while (high - low > 1) {
        size_t mid   = low + (high - low) / 2;
        size_t f_mid  = f_a(test_file, n, mid,   cache, cached);
        size_t f_mid1 = f_a(test_file, n, mid + 1, cache, cached);

        if (f_mid <= f_mid1)
            high = mid;
        else
            low = mid + 1;
    }

    size_t f_low  = f_a(test_file, n, low,  cache, cached);
    size_t f_high = f_a(test_file, n, high, cache, cached);
    size_t best_a = (f_low <= f_high) ? low : high;

    printf("\nOptimal a = %zu  (disk accesses: %zu)\n\n",
           best_a, cache[best_a]);

    /* Show f(a) for all a around the optimum (optional) */
    printf("f(a) near optimum:\n");
    size_t lo = (best_a > 5) ? best_a - 5 : 2;
    size_t hi = (best_a + 5 < b) ? best_a + 5 : b;
    for (size_t a = lo; a <= hi; a++) {
        printf("  a = %3zu  ->  %zu accesses\n",
               a, f_a(test_file, n, a, cache, cached));
    }

    /* Clean up working file */
    delete_file("__a_test.bin");

    return best_a;
}

/* ------------------------------------------------------------------ */
/*  Experiment runner for one (N, a) pair                              */
/* ------------------------------------------------------------------ */

/**
 * Run NUM_SEQUENCES experiments for a given N.
 *
 * @param N             Number of elements.
 * @param a             Arity (same for both algorithms).
 * @param ms_out[out]   Averages for mergesort.
 * @param qs_out[out]   Averages for quicksort.
 */
static void run_experiment(size_t N, size_t a,
                           avg_result_t *ms_out, avg_result_t *qs_out)
{
    double ms_times[NUM_SEQUENCES];
    size_t ms_accs[NUM_SEQUENCES];
    double qs_times[NUM_SEQUENCES];
    size_t qs_accs[NUM_SEQUENCES];

    char fname[128], fcopy[128];

    for (int seq = 0; seq < NUM_SEQUENCES; seq++) {
        /* ---- Generate input ---- */
        snprintf(fname, sizeof(fname), "input_N%zu_%d.bin", N, seq);
        generate_random_array(fname, N);

        /* ---- Mergesort ---- */
        snprintf(fcopy, sizeof(fcopy), "ms_copy_%zu_%d.bin", N, seq);
        copy_file(fcopy, fname, N);

        double t0 = wall_time();
        size_t acc = external_mergesort(fcopy, N, a);
        double t1 = wall_time();

        if (!check_sorted(fcopy, N)) {
            fprintf(stderr, "ERROR: Mergesort unsorted for %s!\n", fcopy);
        }
        ms_times[seq] = (t1 - t0) * 1000.0;
        ms_accs[seq]  = acc;
        delete_file(fcopy);

        /* ---- Quicksort ---- */
        snprintf(fcopy, sizeof(fcopy), "qs_copy_%zu_%d.bin", N, seq);
        copy_file(fcopy, fname, N);

        t0 = wall_time();
        acc = external_quicksort(fcopy, N, a);
        t1 = wall_time();

        if (!check_sorted(fcopy, N)) {
            fprintf(stderr, "ERROR: Quicksort unsorted for %s!\n", fcopy);
        }
        qs_times[seq] = (t1 - t0) * 1000.0;
        qs_accs[seq]  = acc;
        delete_file(fcopy);

        /* Remove input */
        delete_file(fname);

        /* Print per-sequence row */
        printf("%-12zu %-8d %-20.2f %-20zu %-20.2f %-20zu\n",
               N, seq + 1,
               ms_times[seq], ms_accs[seq],
               qs_times[seq], qs_accs[seq]);
    }

    /* ---- Average and standard deviation ---- */
    double sum_ms_t = 0, sum_qs_t = 0;
    double sum_ms_a = 0, sum_qs_a = 0;

    for (int i = 0; i < NUM_SEQUENCES; i++) {
        sum_ms_t += ms_times[i];
        sum_qs_t += qs_times[i];
        sum_ms_a += (double)ms_accs[i];
        sum_qs_a += (double)qs_accs[i];
    }

    ms_out->time_ms  = sum_ms_t / NUM_SEQUENCES;
    qs_out->time_ms  = sum_qs_t / NUM_SEQUENCES;
    ms_out->disk_acc = sum_ms_a / NUM_SEQUENCES;
    qs_out->disk_acc = sum_qs_a / NUM_SEQUENCES;

    double var_ms_t = 0, var_qs_t = 0;
    double var_ms_a = 0, var_qs_a = 0;
    for (int i = 0; i < NUM_SEQUENCES; i++) {
        double d;
        d = ms_times[i] - ms_out->time_ms;  var_ms_t += d * d;
        d = qs_times[i] - qs_out->time_ms;  var_qs_t += d * d;
        d = (double)ms_accs[i] - ms_out->disk_acc; var_ms_a += d * d;
        d = (double)qs_accs[i] - qs_out->disk_acc; var_qs_a += d * d;
    }
    ms_out->time_std = sqrt(var_ms_t / NUM_SEQUENCES);
    qs_out->time_std = sqrt(var_qs_t / NUM_SEQUENCES);
    ms_out->disk_std = sqrt(var_ms_a / NUM_SEQUENCES);
    qs_out->disk_std = sqrt(var_qs_a / NUM_SEQUENCES);

    /* Print averages row */
    printf("%-12s %-8s %-20.2f %-20.2f %-20.2f %-20.2f\n",
           "", "AVG",
           ms_out->time_ms, ms_out->disk_acc,
           qs_out->time_ms, qs_out->disk_acc);
    printf("%-12s %-8s %-20.2f %-20.2f %-20.2f %-20.2f\n\n",
           "", "STD",
           ms_out->time_std, ms_out->disk_std,
           qs_out->time_std, qs_out->disk_std);
}

/* ------------------------------------------------------------------ */
/*  Main                                                               */
/* ------------------------------------------------------------------ */

int main(void)
{
    srand(SEED);

    printf("============================================================\n");
    printf("CC4102 - Tarea 1: Mergesort externo V/S Quicksort externo\n");
    printf("============================================================\n\n");

    printf("Configuration:\n");
    printf("  B = %d bytes (block size)\n", B);
    printf("  M = %d bytes (memory limit)\n", M);
    printf("  Element size = %zu bytes (64-bit)\n", ELEMENT_SIZE);
    printf("  Elems per block = %zu\n", (size_t)ELEMS_PER_BLOCK);
    printf("  Max mem elems   = %zu\n", (size_t)MAX_MEM_ELEMS);
    printf("\n");

    /* ----------------------------------------------------------------
     * Step 1: Generate test file and find optimal a
     * ---------------------------------------------------------------- */
    printf("=== Step 1: Generating test file (16M = %zu elements) ===\n",
           TEST_N);
    {
        double t0 = wall_time();
        generate_random_array("__test_16M.bin", TEST_N);
        double t1 = wall_time();
        printf("  Generated in %.2f s\n", t1 - t0);
    }

    size_t optimal_a = find_optimal_a("__test_16M.bin", TEST_N);
    delete_file("__test_16M.bin");

    printf("=== Optimal arity: a = %zu ===\n\n", optimal_a);

    /* ----------------------------------------------------------------
     * Step 2: Run experiments for each N
     * ---------------------------------------------------------------- */
    printf("=== Step 2: Running experiments ===\n\n");

    /* Table header */
    printf("%-12s %-8s %-20s %-20s %-20s %-20s\n",
           "N (elems)", "Seq",
           "MS Time (ms)", "MS Disk Acc",
           "QS Time (ms)", "QS Disk Acc");
    printf("%-12s %-8s %-20s %-20s %-20s %-20s\n",
           "----------", "---",
           "-------------------", "-------------------",
           "-------------------", "-------------------");

    /* Store results for final summary */
    avg_result_t ms_results[NUM_N];
    avg_result_t qs_results[NUM_N];

    for (int ni = 0; ni < NUM_N; ni++) {
        printf("\n--- N = %zu elements (%zu bytes) ---\n",
               N_VALS[ni], N_VALS[ni] * ELEMENT_SIZE);

        run_experiment(N_VALS[ni], optimal_a,
                       &ms_results[ni], &qs_results[ni]);
    }

    /* ----------------------------------------------------------------
     * Summary table (for plotting / report)
     * ---------------------------------------------------------------- */
    printf("\n=== SUMMARY (copy-paste for plotting) ===\n\n");
    printf("# N_elems  N_bytes  "
           "MS_time(ms)  MS_time_std  MS_disk  MS_disk_std  "
           "QS_time(ms)  QS_time_std  QS_disk  QS_disk_std\n");
    for (int ni = 0; ni < NUM_N; ni++) {
        size_t nb = N_VALS[ni] * ELEMENT_SIZE;
        printf("%10zu  %8zu  "
               "%12.2f  %11.2f  %7.1f  %11.2f  "
               "%12.2f  %11.2f  %7.1f  %11.2f\n",
               N_VALS[ni], nb,
               ms_results[ni].time_ms, ms_results[ni].time_std,
               ms_results[ni].disk_acc, ms_results[ni].disk_std,
               qs_results[ni].time_ms, qs_results[ni].time_std,
               qs_results[ni].disk_acc, qs_results[ni].disk_std);
    }

    printf("\nDone.\n");
    return 0;
}

