    int ms_ok = check_sorted("__ms.bin", N);
    printf("Mergesort: acc=%zu, sorted=%s\n", ms_acc, ms_ok ? "OK" : "FAIL");

    /* Quicksort */
    copy_file("__qs.bin", "__test.bin", N);
    size_t qs_acc = external_quicksort("__qs.bin", N, a);
    int qs_ok = check_sorted("__qs.bin", N);
    printf("Quicksort: acc=%zu, sorted=%s\n", qs_acc, qs_ok ? "OK" : "FAIL");

