    size_t total = 0;
    size_t r1, r2;
    while ((r1 = read_block(f1, b1)) > 0 && (r2 = read_block(f2, b2)) > 0) {
        size_t m = (r1 < r2) ? r1 : r2;
        for (size_t i = 0; i < m && total < N; i++) {
            if (b1[i] != b2[i]) { match = 0; break; }
            total++;
        }
    }
